#include <unistd.h>
#define SOCKET int
#define INVALID_SOCKET -1
#define SOCKET_ERROR -1
#define closesocket close
#endif

#define SERVER_PORT 9999
#define BUFFER_SIZE 4096
#define MAX_PLAYERS 100

enum PacketType {
    PACKET_CONNECT = 1,
    PACKET_DISCONNECT = 2,
    PACKET_POSITION = 3,
    PACKET_SHOOT = 4,
    PACKET_STATE_UPDATE = 5,
    PACKET_HIT_CONFIRM = 6
};

struct Vector3 {
    float x, y, z;
};

struct Player {
    int id;
    std::string name;
    Vector3 position;
    Vector3 rotation;
    int health;
    int ammo;
    sockaddr_in address;
    time_t lastUpdate;
    bool active;
};

struct Packet {
    int type;
    int playerId;
    char data[BUFFER_SIZE - 8];
};

class GameServer {
private:
    SOCKET serverSocket;
    std::unordered_map<int, Player> players;
    std::mutex playersMutex;
    bool running;
    int nextPlayerId;

public:
    GameServer() : running(false), nextPlayerId(1) {
#ifdef _WIN32
        WSADATA wsaData;
        WSAStartup(MAKEWORD(2, 2), &wsaData);
#endif
    }

    ~GameServer() {
        Stop();
#ifdef _WIN32
        WSACleanup();
#endif
    }

    bool Start() {
        serverSocket = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
        if (serverSocket == INVALID_SOCKET) {
            std::cerr << "Failed to create socket" << std::endl;
            return false;
        }

        sockaddr_in serverAddr;
        memset(&serverAddr, 0, sizeof(serverAddr));
        serverAddr.sin_family = AF_INET;
        serverAddr.sin_addr.s_addr = INADDR_ANY;
        serverAddr.sin_port = htons(SERVER_PORT);

        if (bind(serverSocket, (sockaddr*)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
            std::cerr << "Failed to bind socket" << std::endl;
            closesocket(serverSocket);
            return false;
        }

        running = true;
        std::cout << "FPS Game Server started on port " << SERVER_PORT << std::endl;

        std::thread receiveThread(&GameServer::ReceiveLoop, this);
        receiveThread.detach();

        std::thread updateThread(&GameServer::UpdateLoop, this);
        updateThread.detach();

        return true;
    }

    void Stop() {
        running = false;
        if (serverSocket != INVALID_SOCKET) {
            closesocket(serverSocket);
        }
    }

private:
    void ReceiveLoop() {
        char buffer[BUFFER_SIZE];
        sockaddr_in clientAddr;
        socklen_t clientAddrLen = sizeof(clientAddr);

        while (running) {
            int recvLen = recvfrom(serverSocket, buffer, BUFFER_SIZE, 0,
                                   (sockaddr*)&clientAddr, &clientAddrLen);

            if (recvLen > 0) {
                ProcessPacket(buffer, recvLen, clientAddr);
            }
        }
    }

    void ProcessPacket(char* buffer, int length, sockaddr_in& clientAddr) {
        Packet* packet = (Packet*)buffer;

        switch (packet->type) {
            case PACKET_CONNECT:
                HandleConnect(packet, clientAddr);
                break;
            case PACKET_DISCONNECT:
                HandleDisconnect(packet);
                break;
            case PACKET_POSITION:
                HandlePosition(packet);
                break;
            case PACKET_SHOOT:
                HandleShoot(packet);
                break;
        }
    }

    void HandleConnect(Packet* packet, sockaddr_in& clientAddr) {
        std::lock_guard<std::mutex> lock(playersMutex);

        Player newPlayer;
        newPlayer.id = nextPlayerId++;
        memcpy(newPlayer.name, packet->data, sizeof(newPlayer.name));
        newPlayer.position = {0.0f, 0.0f, 0.0f};
        newPlayer.rotation = {0.0f, 0.0f, 0.0f};
        newPlayer.health = 100;
        newPlayer.ammo = 30;
        newPlayer.address = clientAddr;
        newPlayer.lastUpdate = time(nullptr);
        newPlayer.active = true;

        players[newPlayer.id] = newPlayer;

        std::cout << "Player " << newPlayer.name << " connected (ID: " << newPlayer.id << ")" << std::endl;

        char response[BUFFER_SIZE];
        Packet* responsePacket = (Packet*)response;
        responsePacket->type = PACKET_CONNECT;
        responsePacket->playerId = newPlayer.id;
        memcpy(responsePacket->data, &newPlayer.id, sizeof(int));

        sendto(serverSocket, response, sizeof(Packet), 0,
               (sockaddr*)&clientAddr, sizeof(clientAddr));
    }

    void HandleDisconnect(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);

        auto it = players.find(packet->playerId);
        if (it != players.end()) {
            std::cout << "Player " << it->second.name << " disconnected" << std::endl;
            players.erase(it);
        }
    }

    void HandlePosition(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);

        auto it = players.find(packet->playerId);
        if (it != players.end()) {
            memcpy(&it->second.position, packet->data, sizeof(Vector3));
            memcpy(&it->second.rotation, packet->data + sizeof(Vector3), sizeof(Vector3));
            it->second.lastUpdate = time(nullptr);
        }
    }

    void HandleShoot(Packet* packet) {
        std::lock_guard<std::mutex> lock(playersMutex);

        auto shooter = players.find(packet->playerId);
        if (shooter == players.end()) return;

        Vector3 shootDirection;
        int targetPlayerId;
        memcpy(&shootDirection, packet->data, sizeof(Vector3));
        memcpy(&targetPlayerId, packet->data + sizeof(Vector3), sizeof(int));

        shooter->second.ammo--;

        auto target = players.find(targetPlayerId);
        if (target != players.end()) {
            int damage;
            memcpy(&damage, packet->data + sizeof(Vector3) + sizeof(int), sizeof(int));

            target->second.health -= damage;

            std::cout << "Player " << shooter->second.id << " shot Player " 
                      << target->second.id << " for " << damage << " damage" << std::endl;

            if (target->second.health <= 0) {
                target->second.health = 0;
                std::cout << "Player " << target->second.id << " eliminated!" << std::endl;

                char killMsg[BUFFER_SIZE];
                Packet* killPacket = (Packet*)killMsg;
                killPacket->type = PACKET_HIT_CONFIRM;
                killPacket->playerId = target->second.id;
                memcpy(killPacket->data, &shooter->second.id, sizeof(int));

                sendto(serverSocket, killMsg, sizeof(Packet), 0,
                       (sockaddr*)&target->second.address, sizeof(target->second.address));
            }

            char hitMsg[BUFFER_SIZE];
            Packet* hitPacket = (Packet*)hitMsg;
            hitPacket->type = PACKET_HIT_CONFIRM;
            hitPacket->playerId = target->second.id;
            memcpy(hitPacket->data, &damage, sizeof(int));
            memcpy(hitPacket->data + sizeof(int), &target->second.health, sizeof(int));

            sendto(serverSocket, hitMsg, sizeof(Packet), 0,
                   (sockaddr*)&target->second.address, sizeof(target->second.address));
        }
    }

    void UpdateLoop() {
        while (running) {
            std::this_thread::sleep_for(std::chrono::milliseconds(50));
            BroadcastGameState();
        }
    }

    void BroadcastGameState() {
        std::lock_guard<std::mutex> lock(playersMutex);

        if (players.empty()) return;

        char stateBuffer[BUFFER_SIZE];
        Packet* statePacket = (Packet*)stateBuffer;
        statePacket->type = PACKET_STATE_UPDATE;
        statePacket->playerId = 0;

        int offset = 0;
        int playerCount = players.size();
        memcpy(statePacket->data + offset, &playerCount, sizeof(int));
        offset += sizeof(int);

        for (auto& pair : players) {
            Player& player = pair.second;
            memcpy(statePacket->data + offset, &player.id, sizeof(int));
            offset += sizeof(int);
            memcpy(statePacket->data + offset, &player.position, sizeof(Vector3));
            offset += sizeof(Vector3);
            memcpy(statePacket->data + offset, &player.rotation, sizeof(Vector3));
            offset += sizeof(Vector3);
            memcpy(statePacket->data + offset, &player.health, sizeof(int));
            offset += sizeof(int);
            memcpy(statePacket->data + offset, &player.ammo, sizeof(int));
            offset += sizeof(int);
        }

        for (auto& pair : players) {
            Player& player = pair.second;
            if (player.active) {
                sendto(serverSocket, stateBuffer, sizeof(Packet), 0,
                       (sockaddr*)&player.address, sizeof(player.address));
            }
        }
    }
};

